/// <summary>
/// Initializes CustInvoiceJour fields from SalesTable and SalesParmTable
/// </summary>
public void initFromSalesTable(SalesTable _salesTable, SalesParmTable _salesParmTable)
{
    // 1. Let the standard Microsoft code do all its mappings first
    next initFromSalesTable(_salesTable, _salesParmTable);

    // 2. Map the DocumentNum from SalesParmTable securely
    if (_salesParmTable && _salesParmTable.DocumentNum)
    {
        this.DocumentNum = _salesParmTable.DocumentNum;
    }
}
